func menuClass(cfg MenuConfig) string {
	return joinClasses(
		"menu",
		menuDirectionClass(cfg.Direction),
		menuSizeClass(cfg.Size),
		cfg.Class,
	)
}

func menuDirectionClass(d string) string {
	return classFor("menu", d)
}

func menuSizeClass(s string) string {
	switch s {
	case "xs", "sm", "lg", "xl":
		return "menu-" + s
	default:
		return ""
	}
}

func menuEntryClass(item MenuItem, cfg MenuConfig) string {
	var parts []string
	if item.Active {
		parts = append(parts, "menu-active")
	}
	if cfg.UseTooltips && item.Tooltip != "" {
		parts = append(parts, "tooltip")
	}
	return joinClasses(parts...)
}

func menuDisabledLiClass(disabled bool) string {
	if disabled {
		return "menu-disabled"
	}
	return ""
}

func menuAriaDisabled(disabled bool) string {
	if disabled {
		return "true"
	}
	return ""
}

func menuTipAttr(item MenuItem, cfg MenuConfig) string {
	if cfg.UseTooltips && item.Tooltip != "" {
		return item.Tooltip
	}
	return ""
}

